// Valida o webhook secret da Evolution API
// Secret validation: se header presente, valida; se ausente, permite (Evolution API não envia)
const secret = $input.first().json.headers?.['x-webhook-secret'] || $input.first().json.headers?.['X-Webhook-Secret'];
const expected = $env.ML_EVOLUTION_WEBHOOK_SECRET;

if (secret && expected && secret !== expected) {
  throw new Error('[ML-CAPTURA] Webhook secret inválido — requisição rejeitada');
}

const body = $input.first().json.body || $input.first().json;
const event = body.event || body.type;

// Filtra apenas eventos de mensagem — retorna [] para encerrar execução sem erro
const messageEvents = ['messages.upsert', 'messages.update'];
if (!messageEvents.includes(event)) {
  return [];
}

const message = body.data?.message || body.message || {};
const key = body.data?.key || body.key || {};

// Ignora mensagens próprias (fromMe) — retorna [] para encerrar execução
if (key.fromMe) {
  return [];
}

const tipo = message.audioMessage ? 'audio'
           : message.imageMessage ? 'image'
           : message.documentMessage ? 'document'
           : 'text';

const conteudo = message.conversation
               || message.extendedTextMessage?.text
               || null;

return [{
  json: {
    event,
    tipo,
    session_id:   body.instance || $env.ML_EVOLUTION_INSTANCE,
    remote_jid:   key.remoteJid,
    message_id:   key.id,
    conteudo_raw: conteudo,
    audio_url:    message.audioMessage?.url || null,
    duracao_audio: message.audioMessage?.seconds || null,
    metadados:    body,
    area:         'comercial'
  }
}];

// Prepara dados do áudio + transcrição para inserir no Postgres
const payload = $('normalize-payload').first().json;
const whisper = $input.first().json;

return [{
  json: {
    mensagem: {
      area:         payload.area,
      fonte:        'whatsapp',
      session_id:   payload.session_id,
      remote_jid:   payload.remote_jid,
      message_id:   payload.message_id,
      tipo:         'audio',
      conteudo_raw: whisper.text,
      audio_url:    payload.audio_url,
      duracao_audio: payload.duracao_audio,
      status:       'processada',
      metadados:    payload.metadados
    },
    transcricao: {
      texto:     whisper.text,
      idioma:    whisper.language || 'pt',
      confianca: whisper.segments?.[0]?.avg_logprob ? Math.exp(whisper.segments[0].avg_logprob) : null,
      provider:  'groq-whisper'
    }
  }
}];

// Prepara dados de mensagem de texto para inserir no Postgres
const payload = $input.first().json;

return [{
  json: {
    mensagem: {
      area:         payload.area,
      fonte:        'whatsapp',
      session_id:   payload.session_id,
      remote_jid:   payload.remote_jid,
      message_id:   payload.message_id,
      tipo:         'text',
      conteudo_raw: payload.conteudo_raw,
      audio_url:    null,
      duracao_audio: null,
      status:       'processada',
      metadados:    payload.metadados
    },
    transcricao: null
  }
}];

// Log de erro estruturado — não quebra o pipeline
const error = $input.first().json;
console.error('[ML-CAPTURA] Erro no pipeline:', JSON.stringify({
  timestamp: new Date().toISOString(),
  error: error.message || 'Erro desconhecido',
  node: $runIndex
}));
return [{ json: { status: 'error_logged', error: error.message } }];

// Filtro: passa apenas mensagens de áudio
if ($json.tipo !== 'audio') return [];
return [{ json: $json }];

// Filtro: passa apenas mensagens de texto
if ($json.tipo !== 'text') return [];
return [{ json: $json }];
